import {
  CURRENCY_META,
  convertMinorUnits,
  type SupportedCurrency,
} from "@/shared/config/currency-config";
import { useCurrencyStore } from "@/shared/model/currency-store";

export function useCurrencyFormatter() {
  const { currency } = useCurrencyStore();
  const meta = CURRENCY_META[currency];

  /** Format minor units (cents/fils) to display string */
  function formatAmount(
    minorUnits: number,
    opts?: { noDecimals?: boolean },
  ): string {
    const safeAmount = Number.isFinite(minorUnits) ? minorUnits : 0;
    const converted = convertMinorUnits(safeAmount, currency) / 100;
    return new Intl.NumberFormat(meta.locale, {
      style: "currency",
      currency,
      minimumFractionDigits: opts?.noDecimals ? 0 : 2,
      maximumFractionDigits: opts?.noDecimals ? 0 : 2,
    }).format(converted);
  }

  /** Format a value already in major units (dollars/dirhams) for the current currency */
  function formatMajorUnits(majorUnits: number): string {
    const safe = Number.isFinite(majorUnits) ? majorUnits : 0;
    return new Intl.NumberFormat(meta.locale, {
      style: "currency",
      currency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(safe);
  }

  /** Convert user-entered decimal value to minor units for the current currency */
  function toMinorUnits(value: number): number {
    const safe = Number.isFinite(value) ? value : 0;
    return Math.round(safe * 100);
  }

  return {
    formatAmount,
    formatMajorUnits,
    toMinorUnits,
    currency,
    meta,
  } as {
    formatAmount: (
      minorUnits: number,
      opts?: { noDecimals?: boolean },
    ) => string;
    formatMajorUnits: (majorUnits: number) => string;
    toMinorUnits: (value: number) => number;
    currency: SupportedCurrency;
    meta: (typeof CURRENCY_META)[SupportedCurrency];
  };
}

