import { Separator } from "@/shared/ui/shadcn/separator";
import { ArrowRightIcon } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import type { FC } from "react";

export interface DealCardProps {
  requestId: string;
  type: string;
  status: string;
  brand: string;
  model: string;
  amount?: string;
  amountLabel?: string;
  expiresAt?: string;
  expiresLabel?: string;
  imageSrc?: string;
  className?: string;
  href?: string;
  isBuyback?: boolean;
}

const FIRST_LETTER_REGEX = /^\w/;

const getStatusLabel = (status: string, type?: string) => {
  switch (status) {
    case BuybackRequestStatus.New:
    case BuybackRequestStatus.PendingValuation:
      return "Request in Review";
    case BuybackRequestStatus.ValuationReceived:
      return "Valuation Received";
    case "ACTIVE":
      if (type === "DIRECT_SALE") {
        return "Processing Payment";
      }
      return "Payment Received - Buyback Window Active";
    case BuybackRequestStatus.PreAuthOfferSent:
      return "Indicative Offer Sent";
    case BuybackRequestStatus.FinalOfferSent:
      return "Final Offer Sent";
    case BuybackRequestStatus.PreAuthOfferExpired:
    case BuybackRequestStatus.PostAuthOfferExpired:
      return "Expired Offer";
    default:
      return status
        ? status
            .replace(/_/g, " ")
            .toLowerCase()
            .replace(FIRST_LETTER_REGEX, (c) => c.toUpperCase())
        : "Offer Pending";
  }
};

const getStatusTheme = (status: string, isBuyback?: boolean) => {
  if (
    isBuyback ||
    status === BuybackRequestStatus.FinalOfferAccepted ||
    status === "ACTIVE"
  ) {
    return "bg-[#ECFDF5] text-[#047857]";
  }

  const orangeStatuses = [
    BuybackRequestStatus.PreAuthOfferSent,
    BuybackRequestStatus.FinalOfferSent,
    BuybackRequestStatus.ValuationReceived,
    BuybackRequestStatus.PendingAuth,
    BuybackRequestStatus.AuthCompleted,
    BuybackRequestStatus.AssetReceived,
  ];

  if (orangeStatuses.includes(status as BuybackRequestStatus)) {
    return "bg-[#FFEDD5] text-[#9A3412]";
  }

  const redStatuses = [
    BuybackRequestStatus.PreAuthOfferExpired,
    BuybackRequestStatus.PostAuthOfferExpired,
    BuybackRequestStatus.PreAuthVerificationFailed,
    BuybackRequestStatus.PostAuthVerificationFailed,
    BuybackRequestStatus.KYCFailed,
    BuybackRequestStatus.RejectedPreAuthOffer,
    BuybackRequestStatus.RejectedPostAuthOffer,
  ];

  if (redStatuses.includes(status as BuybackRequestStatus)) {
    return "bg-[#FEF2F2] text-[#991B1B]";
  }

  return "bg-[#E2E8F0] text-[#001A8D]";
};

export const DealCard: FC<DealCardProps> = ({
  requestId,
  type,
  brand,
  model,
  amount: manualAmount,
  amountLabel: manualAmountLabel,
  expiresAt: manualExpiresAt,
  expiresLabel: manualExpiresLabel,
  imageSrc,
  status,
  className,
  isBuyback,
  href,
}) => {
  const { data: buyback } = useBuybackDetails(requestId, !!isBuyback);
  const { data: request } = useBuybackRequest(requestId, !isBuyback);

  let displayAmount = manualAmount;
  let displayAmountLabel = manualAmountLabel || "Final Item Valuation";

  if (isBuyback && buyback?.computedDetails) {
    const price = buyback.computedDetails.purchasePriceCents;
    displayAmount = `$${(price / 100).toLocaleString("en-US")}`;
    displayAmountLabel = "Buyback Price";
  } else if (!isBuyback && request) {
    const postOffer = request.postAuthOffer?.data?.amountCents;
    const preOffer = request.preAuthOffer?.data?.amountCents;

    if (postOffer) {
      displayAmount = `$${(postOffer / 100).toLocaleString("en-US")}`;
      displayAmountLabel = "Final Indicative Offer Approval";
    } else if (preOffer) {
      displayAmount = `$${(preOffer / 100).toLocaleString("en-US")}`;
      displayAmountLabel = "Indicative Offer Amount";
    }
  }

  let displayExpires = manualExpiresAt;
  let displayExpiresLabel = manualExpiresLabel || "Expires";

  if (isBuyback && buyback?.computedDetails?.dueDate) {
    displayExpires = new Date(
      buyback.computedDetails.dueDate,
    ).toLocaleDateString("en-US");
    displayExpiresLabel = "Due Date";
  } else if (!isBuyback && request) {
    const orangeStatuses = [
      BuybackRequestStatus.PreAuthOfferSent,
      BuybackRequestStatus.FinalOfferSent,
    ];

    if (orangeStatuses.includes(status as BuybackRequestStatus)) {
      const offerDate =
        request.postAuthOffer?.createdAt ||
        request.preAuthOffer?.createdAt ||
        request.createdAt;
      if (offerDate) {
        const expiryDate = new Date(offerDate);
        expiryDate.setHours(expiryDate.getHours() + 48);
        displayExpires = expiryDate.toLocaleDateString("en-US", {
          month: "short",
          day: "numeric",
          year: "numeric",
        });
        displayExpiresLabel = "Expires";
      }
    }
  }

  const typeToShow =
    type === "DIRECT_SALE" ? "Permanent sale" : "Sale with Buyback";

  const statusBadge = (
    <div
      className={cn(
        "inline-flex w-fit items-center gap-1 rounded-lg px-2 py-1 font-medium text-sm leading-[150%] tracking-[-1%] max-md:my-2",
        getStatusTheme(status, isBuyback),
      )}
    >
      {getStatusLabel(status, type)}
    </div>
  );

  const content = (
    <div className="new-design flex h-full w-full flex-col gap-4 overflow-hidden bg-[#EEE9E3] p-4 sm:flex-row">
      <div className="relative h-[320px] w-full bg-[#F5F5F0] sm:w-[40%] md:h-[320px] lg:h-[280px]">
        <Image
          alt={`${brand} ${model}`}
          className="rounded-sm object-cover transition-transform duration-500 group-hover:scale-[102%]"
          fill
          priority
          src={
            imageSrc ||
            "https://img-edg.joomcdn.net/7c43751efdc76734f21660ec9f2f8860acd937b1_original.jpeg"
          }
          unoptimized
        />
      </div>

      <div className="flex flex-col justify-between sm:h-auto sm:w-[60%]">
        <div className="flex flex-col py-2 font-new-sans">
          <div className="space-y-3">
            <div className="inline-block">
              <span className="rounded-md bg-[#D6D3D1] px-2 py-1 font-medium text-sm leading-[150%] tracking-[-1%]">
                {typeToShow} — {requestId?.slice(0, 8).toUpperCase()}
              </span>
            </div>

            <div className="space-y-1">
              <h2 className="font-semibold text-xl leading-[24px] tracking-[-1%] sm:text-2xl">
                {brand} {model}
              </h2>
              <p className="text-sm leading-[150%] tracking-[-1%] opacity-70">
                Model: {model}
              </p>
            </div>
          </div>

          <Separator className="my-4 bg-[#D6D3D1]" />

          <div className="space-y-3 font-new-sans">
            {displayAmount ? (
              <div className="flex flex-col gap-2">
                <div>
                  <p className="text-[#60605E] text-sm">{displayAmountLabel}</p>
                  <p className="font-semibold text-xl leading-[150%] tracking-[-1%]">
                    {displayAmount}
                  </p>
                </div>
                {statusBadge}
              </div>
            ) : (
              statusBadge
            )}
          </div>
        </div>

        <div className="flex w-full items-center justify-between border-transparent border-t pt-4 font-new-sans">
          <div>
            {displayExpires && (
              <p className="whitespace-nowrap text-[#60605E] text-sm">
                {displayExpiresLabel}:{" "}
                <span className="font-bold">{displayExpires}</span>
              </p>
            )}
          </div>
          <Button
            className="h-9 w-9 border-[hsl(var(--outline-gray))]"
            size={"icon"}
            variant={"outline"}
          >
            <ArrowRightIcon className="text-[--outline-gray]" size={16} />
          </Button>
        </div>
      </div>
    </div>
  );

  const cardClassName = cn(
    "group flex w-full overflow-hidden rounded-2xl border border-[#EEE9E3] bg-white transition-all duration-300",
    "min-h-0 sm:min-h-[280px]",
    href && "cursor-pointer hover:border-gray-300 hover:shadow-lg",
    className,
  );

  return href ? (
    <Link className={cardClassName} href={href}>
      {content}
    </Link>
  ) : (
    <div className={cardClassName}>{content}</div>
  );
};

